class Solution:
    def hammingDistance(self, x, y):
        # Compare bit strings position by position instead of popcount
        bx = bin(x)[2:]
        by = bin(y)[2:]
        width = max(len(bx), len(by))
        bx = bx.zfill(width)
        by = by.zfill(width)
        return sum(1 for a, b in zip(bx, by) if a != b)

